function getRawSecret(): Uint8Array {
  const fromEnv = process.env['FORGE_SESSION_SECRET'];
  if (fromEnv && fromEnv.trim().length >= 32) {
    return new TextEncoder().encode(fromEnv.trim());
  }

  if (process.env['NODE_ENV'] === 'production') {
    throw new Error(
      '[FORGE] FORGE_SESSION_SECRET must be set in production (min 32 chars). ' +
      'Generate one with: openssl rand -hex 32',
    );
  }

  // Dev fallback: auto-generate + persist so restarts keep cookies valid.
  const secretPath = join(process.cwd(), '.forge', '.session-secret');
  try {
    const persisted = readFileSync(secretPath, 'utf8').trim();
    if (persisted.length >= 32) {
      return new TextEncoder().encode(persisted);
    }
  } catch {
    // File doesn't exist yet — generate below.
  }

  // Generate a 64-char hex secret (256 bits of entropy).
  const raw = Buffer.from(
    Array.from({ length: 32 }, () => Math.floor(Math.random() * 256)),
  ).toString('hex');

  try {
    mkdirSync(join(process.cwd(), '.forge'), { recursive: true });
    writeFileSync(secretPath, raw, { mode: 0o600 });
  } catch {
    // If we can't persist (read-only FS), continue with in-memory secret.
  }

  return new TextEncoder().encode(raw);
}

