async function getSecretKey(): Promise<CryptoKey> {
  if (_cryptoKey) return _cryptoKey;
  if (_cryptoKeyPromise) return _cryptoKeyPromise;

  // getRawSecret() throws synchronously in prod when env var is absent.
  const raw = getRawSecret();
  _cryptoKeyPromise = importHmacKey(raw).then((key) => {
    _cryptoKey = key;
    _cryptoKeyPromise = null;
    return key;
  });
  return _cryptoKeyPromise;
}

