export function readSessionCookie(req: Request): string | null {
  // Express populates req.cookies only when cookie-parser is registered.
  // Fall back to manual header parse so this module works even without it.
  const cookieHeader = req.headers.cookie ?? '';
  for (const part of cookieHeader.split(';')) {
    const [rawName, ...rest] = part.trim().split('=');
    if (rawName?.trim() === SESSION_COOKIE_NAME && rest.length > 0) {
      return rest.join('=').trim();
    }
  }
  return null;
}

