export async function verifySession(
  token: string,
): Promise<Result<SessionPayload, ErrorEnvelope>> {
  try {
    const key = await getSecretKey();
    const { payload } = await jwtVerify(token, key, { algorithms: ['HS256'] });

    const sub = payload.sub;
    const email = payload['email'];
    const role  = payload['role'];

    if (
      typeof sub   !== 'string' || !sub ||
      typeof email !== 'string' || !email ||
      typeof role  !== 'string' || !role
    ) {
      return Err(createErrorEnvelope('session_invalid', 'Session payload is missing required fields'));
    }

    return Ok({ sub, email, role });
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    const isExpired = message.includes('expired') || message.includes('JWTExpired');
    return Err(createErrorEnvelope(
      isExpired ? 'session_expired' : 'session_invalid',
      message,
    ));
  }
}

