export function getErrorGuidance(
  errorCode: string,
  context: ErrorContext = {},
): ErrorGuidance {
  // Use Object.prototype.hasOwnProperty to avoid prototype pollution issues
  const guidance = Object.prototype.hasOwnProperty.call(ERROR_GUIDANCE_CATALOG, errorCode)
    ? ERROR_GUIDANCE_CATALOG[errorCode]
    : undefined;

  if (!guidance) {
    return {
      suggestions: ["Check the error message for details", "Run 'forge doctor' to diagnose common issues"],
      exampleCommands: ["forge doctor", "forge --help"],
      documentationLinks: ["https://github.com/navistone/engineering-agent-standards"],
    };
  }

  // Replace context placeholders in suggestions and commands
  const suggestions = guidance.suggestions.map(s => replaceContextPlaceholders(s, context));
  const exampleCommands = guidance.exampleCommands.map(c => replaceContextPlaceholders(c, context));

  return {
    suggestions,
    exampleCommands,
    documentationLinks: guidance.documentationLinks,
  };
}

