export async function handleGetCallees(rawInput: unknown): Promise<Result<ToolResult, ErrorEnvelope>> {
  const parsed = parseInput(rawInput);
  if (!parsed.ok) return Err(parsed.error);
  const { symbol_qname, repo } = parsed.value;

  const result = await getCallees(symbol_qname, repo);
  if (!result.ok) return Err(result.error);

  const callees = result.value.results.map((r) => ({
    qname: r.qualified_name,
    file_path: r.file_path,
  }));
  return Ok({
    content: { callees },
    summary: `get_callees(${symbol_qname}): ${callees.length} callee(s)`,
  });
}

function parseInput(raw: unknown): Result<GetCalleesInput, ErrorEnvelope> {
  if (typeof raw !== 'object' || raw === null) {
    return Err(createErrorEnvelope('tool_input_invalid', 'get_callees: input must be an object'));
  }
  const v = raw as Record<string, unknown>;
  if (typeof v['symbol_qname'] !== 'string' || v['symbol_qname'].length === 0) {
    return Err(createErrorEnvelope('tool_input_invalid', 'get_callees: symbol_qname must be a non-empty string'));
  }
  if (typeof v['repo'] !== 'string' || v['repo'].length === 0) {
    return Err(createErrorEnvelope('tool_input_invalid', 'get_callees: repo must be a non-empty string'));
  }
  return Ok({ symbol_qname: v['symbol_qname'], repo: v['repo'] });
}

