getRemaining(identifier: string): number {
  const now = Date.now();
  const windowStart = now - this.config.windowMs;

  const clientRequests = this.requests.get(identifier) || [];
  const recentRequests = clientRequests.filter(req => req.timestamp > windowStart);

  return Math.max(0, this.config.maxRequests - recentRequests.length);
}

getResetTime(identifier: string): number {
  const now = Date.now();
  const windowStart = now - this.config.windowMs;

  const clientRequests = this.requests.get(identifier) || [];
  const recentRequests = clientRequests.filter(req => req.timestamp > windowStart);

  if (recentRequests.length === 0) {
    return 0;
  }

  // Time until oldest request expires
  const oldestRequest = recentRequests[0];
  if (!oldestRequest) {
    return 0;
  }

  const resetTime = oldestRequest.timestamp + this.config.windowMs - now;

  return Math.max(0, resetTime);
}

isAllowed(identifier: string): boolean {
  const now = Date.now();
  const windowStart = now - this.config.windowMs;

  // Get existing requests for this identifier
  let clientRequests = this.requests.get(identifier) || [];

  // Remove requests outside the current window
  clientRequests = clientRequests.filter(req => req.timestamp > windowStart);

  // Check if limit is exceeded
  if (clientRequests.length >= this.config.maxRequests) {
    // Update the map with filtered requests
    this.requests.set(identifier, clientRequests);
    return false;
  }

  // Add new request
  clientRequests.push({ timestamp: now, ip: identifier });
  this.requests.set(identifier, clientRequests);

  return true;
}

