async function _get<T>(path: string, opts?: _RequestOptions): Promise<Result<T, ErrorEnvelope>> {
  const controller = opts?.timeoutMs !== undefined ? new AbortController() : null;
  const timer = controller !== null && opts?.timeoutMs !== undefined
    ? setTimeout(() => controller.abort(), opts.timeoutMs)
    : null;
  try {
    const res = await fetch(`${BASE_URL}${path}`, {
      headers: _outboundHeaders(opts?.bearerToken),
      ...(controller !== null ? { signal: controller.signal } : {}),
    });
    if (!res.ok) {
      // Best-effort error body; fall back to statusText if body read fails.
      const text = await res.text().catch(() => res.statusText);
      return Err(createErrorEnvelope('code_indexer_http_error', `${res.status} ${text}`));
    }
    return Ok((await res.json()) as T);
  } catch (err) {
    const message = err instanceof Error
      ? (err.name === 'AbortError' ? 'request timed out' : err.message)
      : String(err);
    return Err(createErrorEnvelope('code_indexer_fetch_failed', message));
  } finally {
    if (timer !== null) clearTimeout(timer);
  }
}

function _outboundHeaders(
  userBearer: string | null | undefined,
  extra?: Record<string, string>,
): Record<string, string> {
  const bearer = userBearer ?? _moduleBearerToken;
  if (bearer) {
    return { ...authHeaders(true), Authorization: `Bearer ${bearer}`, ...(extra ?? {}) };
  }
  return { ...authHeaders(), ...(extra ?? {}) };
}

