async function resolveSessionExpiry(req: Request): Promise<string | null> {
  const raw = readSessionCookie(req);
  if (!raw) return null;
  const verifyResult = await verifySession(raw);
  if (!verifyResult.ok) return null;
  // verifySession returns the payload; we re-decode to read `exp` since
  // verifySession's surface doesn't currently expose iat/exp claims.
  try {
    const [, payloadB64] = raw.split('.');
    if (!payloadB64) return null;
    const payloadJson = Buffer.from(payloadB64, 'base64url').toString('utf8');
    const claims = JSON.parse(payloadJson) as { exp?: unknown };
    if (typeof claims.exp !== 'number') return null;
    return new Date(claims.exp * 1000).toISOString();
  } catch {
    return null;
  }
}

